    int minimumDeleteSum(string s1, string s2) {
        int sum = 0;
        int i = 0, j = 0;
        while (i < s1.size() || j < s2.size()) {
            if (i < s1.size() && j < s2.size()) {
                if (s1[i] == s2[j]) {
                    i++;
                    j++;
                } else {
                    sum += s1[i] < s2[j] ? s1[i++] : s2[j++];
                }
            } else if (i < s1.size()) {
                sum += s1[i++];
            } else {
                sum += s2[j++];
            }
        }
        return sum;
    }
};```
